INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2020-02-15 15:00:00", 1002, "愛情たっぷりのチョコレートケー\nキを完成させよう！\n超キュートなタップゲーム！", "bgm_M199", "bgm_M199_juke", "", 10000, 1001, "2030/12/31 15:00:00", "お兄ちゃん争奪！\nどっちのチョコがおいしいでSHOW");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2020-02-15 15:00:00", 1003, "大回転！クウカ！\n最高のエクスタシーここにあり！\n引っ張って飛ばす、空の旅！", "bgm_M227", "bgm_M227_juke", "", 10000, 1002, "2030/12/31 15:00:00", "クウカ大回転\n飛行道中エクスタシー");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2020-02-15 15:00:00", 1004, "これぞ琉球魂！\n押し寄せるマジムンをなぎ倒す\n爽快アクションゲーム！", "bgm_M249", "bgm_M249_juke", "", 10000, 1003, "2030/12/31 15:00:00", "カオリのマブイ式空手道場");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2020-02-15 15:00:00", 1005, "白熱バトル！\nドラゴンズネスト流\nタイマン式頭脳しりとり！", "bgm_M277", "bgm_M277_juke", "", 10000, 1004, "2030/12/31 15:00:00", "大激戦！しりとりドラゴンズ");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2020-05-31 12:00:00", 1006, "キミはチーズを守り抜けるか！？\n瞬発力が試される\n反射神経系カジュアルゲーム！", "bgm_M355_Lofi", "bgm_M355_Lofi_juke", "", 10000, 1005, "2030/12/31 15:00:00", "チュウチュウパニック！\nチーズお守り大作戦！");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2020-08-15 15:00:00", 1007, "目指せホームランバッター！\nミートタイミングがカギを握る\nスポーツアクションゲーム！", "bgm_M399", "bgm_M399", "", 10000, 1006, "2030/12/31 15:00:00", "猛訓打撃道！\nミサトのホームランドリル");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2021-08-31 12:00:00", 1008, "カルミナファン大興奮！\nライブ応援グッズを手に入れて\n目指せ「カルミナ神推し」！", "bgm_M500", "bgm_M500", "", 10000, 1007, "2030/12/31 15:00:00", "カルミナサマーライブ\nライブ会場 グッズエリア");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2021-12-18 15:00:00", 1009, "レッツ・クッキング！\nミヤコとプリンを作って食べて\nプリンの道を極めよう！", "bgm_M540", "bgm_M540", "", 10000, 1008, "2030/12/31 15:00:00", "ミヤコ's キッチン　究極への道");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2022/02/28 11:59:59", "2022-02-15 15:00:00", 1010, "５人チームで力を合わせて多種多\n様なジャンルのクイズに挑戦！\n目指せ、クイズプリンセス！", "bgm_M569", "bgm_M569", "ランドソルクイズコネクト！", 0, 1009, "2022/02/15 15:00:00", "Happy Anniv.スペシャル　\nランドソルクイズコネクト！");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2022-07-18 15:00:00", 1011, "砂浜駆けるプリンセス！\nハチャメチャなコースに挑む、\n南の島のビーチフラッグス！", "bgm_M605", "bgm_M605", "", 10000, 1010, "2030/12/31 15:00:00", "駆けろ常夏！\nアルティメットビーチフラッグス");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2023-09-18 15:00:00", 1012, "めざせ全問正解！\nキャルとスズナと放課後の教室で\n二人きりのクイズ勉強会！", "bgm_MC068", "bgm_MC068", "放課後クイズエデュケーション　{0}", 10000, 1012, "2030/12/31 15:00:00", "キャルとスズナの\n放課後クイズエデュケーション");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2024-04-18 15:00:00", 1013, "魔物はびこる街道を突き進め！\n【王宮騎士団(NIGHTMARE)】\nの兵たちを率い、訓練に挑戦だ！", "bgm_MC141", "bgm_MC141", "行軍（マーチ）A-Go-Go！", 10000, 1013, "2030/12/31 15:00:00", "エリコとマコトの\n行軍（マーチ）A-Go-Go！");
INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("2030/12/31 15:00:00", "2024-11-18 15:00:00", 1014, "戦車バトル大会開幕！\n組み上げたオリジナルマシンで\n頂点を目指せ！", "bgm_MC199", "bgm_MC199_Battle", "激突！破壊！\nイリーガルタンクウォー", 10000, 1014, "2030/12/31 15:00:00", "激突！破壊！\nイリーガルタンクウォー");
